export default function IconSearch() {
  const [query, setQuery] = useState('')
  const [selectedLib, setSelectedLib] = useState<string>('all')
  const { copy, copied } = useClipboard()

  const filteredIcons = useMemo(() => {
    const q = query.toLowerCase()
    const results: Array<{ lib: string; icon: string; url: string }> = []
    
    for (const lib of iconLibraries) {
      if (selectedLib !== 'all' && selectedLib !== lib.name) continue
      
      const matches = lib.icons.filter(icon => icon.includes(q))
      for (const icon of matches) {
        results.push({ lib: lib.name, icon, url: lib.url })
      }
    }
    
    return results.slice(0, 100)
  }, [query, selectedLib])

  const copyIconName = (lib: string, icon: string) => {
    const formatted = lib === 'Lucide' ? `<${icon.split('-').map((w, i) => i === 0 ? w.charAt(0).toUpperCase() + w.slice(1) : w.charAt(0).toUpperCase() + w.slice(1)).join('')} />` : icon
    copy(formatted)
  }

  return (
    <ToolLayout meta={meta} onReset={() => setQuery('')}>
      <div className="flex flex-col gap-4">
        <div className="flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-text-muted" />
            <input
              className="tool-input pl-10 w-full"
              placeholder="搜索图标名称..."
              value={query}
              onChange={e => setQuery(e.target.value)}
            />
          </div>
          <select
            className="tool-input w-32"
            value={selectedLib}
            onChange={e => setSelectedLib(e.target.value)}
          >
            <option value="all">全部</option>
            {iconLibraries.map(lib => (
              <option key={lib.name} value={lib.name}>{lib.name}</option>
            ))}
          </select>
        </div>

        <div className="text-xs text-text-muted">
          找到 {filteredIcons.length} 个图标
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-2">
          {filteredIcons.map(({ lib, icon }) => (
            <button
              key={`${lib}-${icon}`}
              onClick={() => copyIconName(lib, icon)}
              className="p-3 rounded-lg bg-bg-surface border border-border-base hover:border-accent hover:bg-accent/5 transition-colors flex flex-col items-center gap-2 group"
            >
              <div className="w-8 h-8 flex items-center justify-center text-text-muted group-hover:text-accent">
                {copied ? <Check className="w-5 h-5 text-accent" /> : <span className="text-xs font-mono">{icon.slice(0, 2).toUpperCase()}</span>}
              </div>
              <span className="text-xs text-text-secondary truncate w-full text-center">{icon}</span>
              <span className="text-[10px] text-text-muted">{lib}</span>
            </button>
          ))}
        </div>

        {filteredIcons.length === 0 && query && (
          <div className="text-center py-8 text-text-muted">
            未找到匹配的图标
          </div>
        )}

        <div className="flex flex-wrap gap-2 text-xs text-text-muted">
          <span>图标来源：</span>
          {iconLibraries.map(lib => (
            <a
              key={lib.name}
              href={lib.url}
              target="_blank"
              rel="noopener noreferrer"
              className="text-accent hover:underline flex items-center gap-1"
            >
              {lib.name}
              <ExternalLink className="w-3 h-3" />
            </a>
          ))}
        </div>
      </div>
    </ToolLayout>
  )
}
